/*
 * blog-post.js - renders a single blog post client-side.
 *
 * Expects the host page (generated by scripts/build-blog.mjs) to provide:
 *   <script type="text/markdown" id="raw-markdown">...front-matter-stripped markdown...</script>
 *   <script type="application/json" id="post-meta">{ slug, title, prev, next }</script>
 *   <div id="post-content"></div>
 *   <nav id="post-toc"></nav>
 *   <div id="reading-progress"></div>
 * and load marked, DOMPurify, highlight.js and KaTeX (+ auto-render) from CDN
 * before this script runs.
 */
(function () {
  function escapeHtml(str) {
    return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  }

  // ---- 1. Protect math from the markdown/emphasis parser ----------------
  function extractMath(md) {
    var store = [];
    function stash(match) {
      store.push(match);
      return 'MATHPLACEHOLDER' + (store.length - 1) + 'ENDPLACEHOLDER';
    }
    md = md.replace(/\$\$([\s\S]+?)\$\$/g, stash);
    md = md.replace(/\$([^\$\n]+?)\$/g, stash);
    return { md: md, store: store };
  }

  function restoreMath(html, store) {
    store.forEach(function (mathSrc, i) {
      var placeholder = 'MATHPLACEHOLDER' + i + 'ENDPLACEHOLDER';
      html = html.split(placeholder).join(escapeHtml(mathSrc));
    });
    return html;
  }

  // ---- 2. Markdown renderer: figures with captions + optional video -----
  function buildRenderer() {
    var renderer = new marked.Renderer();
    renderer.image = function (href, title, text) {
      var isVideo = /\.(mp4|webm|ogv)(\?.*)?$/i.test(href || '');
      var media = isVideo
        ? '<video controls playsinline preload="metadata"><source src="' + href + '">Your browser does not support the video tag.</video>'
        : '<img src="' + href + '" alt="' + escapeHtml(text || '') + '" loading="lazy">';
      var caption = title ? '<figcaption>' + escapeHtml(title) + '</figcaption>' : '';
      return '<figure>' + media + caption + '</figure>';
    };
    return renderer;
  }

  // ---- 3. Slugify heading text for anchors --------------------------------
  function slugify(text) {
    return text
      .toLowerCase()
      .trim()
      .replace(/[^a-z0-9\s-]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-');
  }

  function buildToc(container, tocEl) {
    var headings = container.querySelectorAll('h2, h3');
    if (!headings.length) {
      var wrap = tocEl.closest('.post-toc');
      if (wrap) wrap.style.display = 'none';
      return;
    }
    var used = {};
    var items = [];
    headings.forEach(function (h) {
      var base = slugify(h.textContent);
      var id = base;
      var n = 2;
      while (used[id]) { id = base + '-' + n++; }
      used[id] = true;
      h.id = id;
      items.push({ id: id, text: h.textContent, level: h.tagName.toLowerCase() });
    });

    var html = '<div class="post-toc-label">Contents</div><ol>' + items.map(function (item) {
      return '<li><a href="#' + item.id + '"' + (item.level === 'h3' ? ' class="is-h3"' : '') + '>' + escapeHtml(item.text) + '</a></li>';
    }).join('') + '</ol>';
    tocEl.innerHTML = html;

    var links = tocEl.querySelectorAll('a');
    if ('IntersectionObserver' in window) {
      var observer = new IntersectionObserver(function (entries) {
        entries.forEach(function (entry) {
          var link = tocEl.querySelector('a[href="#' + entry.target.id + '"]');
          if (!link) return;
          if (entry.isIntersecting) {
            links.forEach(function (l) { l.classList.remove('active'); });
            link.classList.add('active');
          }
        });
      }, { rootMargin: '-15% 0px -70% 0px' });
      headings.forEach(function (h) { observer.observe(h); });
    }
  }

  // ---- 4. Reading progress bar --------------------------------------------
  function initProgressBar() {
    var bar = document.getElementById('reading-progress');
    if (!bar) return;
    function update() {
      var doc = document.documentElement;
      var scrollTop = window.scrollY || doc.scrollTop;
      var height = doc.scrollHeight - doc.clientHeight;
      var pct = height > 0 ? (scrollTop / height) * 100 : 0;
      bar.style.width = pct + '%';
    }
    window.addEventListener('scroll', update, { passive: true });
    window.addEventListener('resize', update);
    update();
  }

  // ---- 5. Copy link + share buttons ---------------------------------------
  function initActions(meta) {
    var copyBtn = document.getElementById('copy-link-btn');
    if (copyBtn) {
      copyBtn.addEventListener('click', function () {
        var label = copyBtn.querySelector('.label') || copyBtn;
        var original = label.textContent;
        navigator.clipboard.writeText(window.location.href).then(function () {
          label.textContent = 'Copied!';
          setTimeout(function () { label.textContent = original; }, 1500);
        });
      });
    }

    var shareX = document.getElementById('share-x-btn');
    if (shareX) {
      shareX.addEventListener('click', function () {
        var url = encodeURIComponent(window.location.href);
        var text = encodeURIComponent(meta.title || document.title);
        window.open('https://twitter.com/intent/tweet?text=' + text + '&url=' + url, '_blank', 'noopener,noreferrer,width=550,height=420');
      });
    }

    var shareLi = document.getElementById('share-linkedin-btn');
    if (shareLi) {
      shareLi.addEventListener('click', function () {
        var url = encodeURIComponent(window.location.href);
        window.open('https://www.linkedin.com/sharing/share-offsite/?url=' + url, '_blank', 'noopener,noreferrer,width=550,height=550');
      });
    }
  }

  // ---- 6. Prev / next navigation -------------------------------------------
  function initPostNav(meta) {
    var nav = document.getElementById('post-nav');
    if (!nav) return;
    var prevHtml = meta.prev
      ? '<a class="post-nav-link prev" href="' + encodeURIComponent(meta.prev.slug) + '.html">' +
          '<span class="post-nav-label">&larr; Previous</span>' +
          '<span class="post-nav-title">' + escapeHtml(meta.prev.title) + '</span></a>'
      : '<span></span>';
    var nextHtml = meta.next
      ? '<a class="post-nav-link next" href="' + encodeURIComponent(meta.next.slug) + '.html">' +
          '<span class="post-nav-label">Next &rarr;</span>' +
          '<span class="post-nav-title">' + escapeHtml(meta.next.title) + '</span></a>'
      : '<span></span>';
    nav.innerHTML = prevHtml + nextHtml;
  }

  // ---- Main ------------------------------------------------------------------
  function init() {
    var mdEl = document.getElementById('raw-markdown');
    var contentEl = document.getElementById('post-content');
    var tocEl = document.getElementById('post-toc');
    var metaEl = document.getElementById('post-meta');
    if (!mdEl || !contentEl) return;

    var meta = {};
    try { meta = JSON.parse(metaEl.textContent); } catch (e) {}

    var raw = mdEl.textContent;
    var extracted = extractMath(raw);
    marked.setOptions({ renderer: buildRenderer(), breaks: false, gfm: true });
    var html = marked.parse(extracted.md);
    html = restoreMath(html, extracted.store);

    if (window.DOMPurify) {
      html = DOMPurify.sanitize(html, {
        ADD_TAGS: ['figure', 'figcaption', 'video', 'source'],
        ADD_ATTR: ['controls', 'playsinline', 'preload', 'loading']
      });
    }

    contentEl.innerHTML = html;

    if (window.hljs) {
      contentEl.querySelectorAll('pre code').forEach(function (block) {
        hljs.highlightElement(block);
      });
    }

    if (window.renderMathInElement) {
      renderMathInElement(contentEl, {
        delimiters: [
          { left: '$$', right: '$$', display: true },
          { left: '$', right: '$', display: false }
        ],
        throwOnError: false
      });
    }

    if (tocEl) buildToc(contentEl, tocEl);
    initProgressBar();
    initActions(meta);
    initPostNav(meta);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
